import{_ as o,c as p,a as t,t as a,d as s,o as r}from"./app.a012ad08.js";var i="/vitepress-laravel-vue/assets/create-collection.633d1253.jpg",c="/vitepress-laravel-vue/assets/login.0cb78e0e.jpg",l="/vitepress-laravel-vue/assets/surprise.82136068.jpg",u="/vitepress-laravel-vue/assets/pre-request.ada44c33.jpg",d="/vitepress-laravel-vue/assets/csrf-cookie.67618f68.jpg",h="/vitepress-laravel-vue/assets/xxsrftoken.5817a6e0.jpg",k="/vitepress-laravel-vue/assets/unauthenticated.e20702fc.jpg",m="/vitepress-laravel-vue/assets/cookies.51f5b6ec.jpg",n="/vitepress-laravel-vue/assets/userslist.034a76a7.jpg",g="/vitepress-laravel-vue/assets/localhostport.b3f95f90.jpg",v="/vitepress-laravel-vue/assets/envname.c595006e.jpg",f="/vitepress-laravel-vue/assets/logout.3923a9e5.jpg";const R='{"title":"Laravel Sanctum (Airlock) with Postman","description":"","frontmatter":{},"headers":[{"level":2,"title":"The jist of it","slug":"the-jist-of-it"},{"level":2,"title":"Create a Postman Collection","slug":"create-a-postman-collection"},{"level":2,"title":"Create an environment","slug":"create-an-environment"},{"level":2,"title":"Add a pre-request script","slug":"add-a-pre-request-script"},{"level":2,"title":"Make authenticated requests","slug":"make-authenticated-requests"},{"level":2,"title":"A quick note on other web routes","slug":"a-quick-note-on-other-web-routes"}],"relativePath":"laravel/laravel-with-postman.md"}',w={},y=s('<h1 id="laravel-sanctum-airlock-with-postman" tabindex="-1">Laravel Sanctum (Airlock) with Postman <a class="header-anchor" href="#laravel-sanctum-airlock-with-postman" aria-hidden="true">#</a></h1><p>Remember that you are using Laravel as an API. And to test it with Postman, this requires a bit more work than just attaching a token (unless you&#39;re using token-based authentication with Sanctum).</p><p>If you&#39;re building a SPA and want to test your endpoints with cookie-based authentication in Postman, here&#39;s how to do it.</p><h2 id="the-jist-of-it" tabindex="-1">The jist of it <a class="header-anchor" href="#the-jist-of-it" aria-hidden="true">#</a></h2><p>Because Sanctum uses cookie-based authentication and hits CSRF protected endpoints like /login and /logout, we need to make sure we&#39;re sending a CSRF token with Postman. We get this by sending a request to /sanctum/csrf-cookie first. We&#39;ll also need to make sure the Referrer is properly sent for future requests for Sanctum to allow them.</p><p>Estoy probando esto con un proyecto Laravel correctamente configurado con Sanctum, que permite solicitudes de localhost, en t\xE9rminos de dominios CORS y Sanctum.</p><p>We&#39;re testing this with a <a href="./../guide/setup-laravel-api.html">Laravel Project properly configured with Sanctum</a>, that allows requests from localhost, in terms of both CORS and Sanctum domains.</p><h2 id="create-a-postman-collection" tabindex="-1">Create a Postman Collection <a class="header-anchor" href="#create-a-postman-collection" aria-hidden="true">#</a></h2><p>We&#39;d recommend creating a Postman collection so we can apply our pre-request script (in a moment) to all endpoints.</p><p><img src="'+i+'" alt="Create collection"></p><p>Once the collection is created, this makes it easier to apply a pre-request script to all endpoints under that collection. It also helps keep everything nice and tidy.</p><h2 id="create-an-environment" tabindex="-1">Create an environment <a class="header-anchor" href="#create-an-environment" aria-hidden="true">#</a></h2><p>We&#39;re going to be setting a CSRF token in our environment variables in Postman, so we need to create a Postman environment.</p><p>Click the cog in the top right of Postman, click Add and give your environment a name (mine&#39;s forum). Click Add again and switch to your environment in the top right (see top right of screenshot).</p><p><img src="'+c+'" alt="login"></p><h2 id="add-a-pre-request-script" tabindex="-1">Add a pre-request script <a class="header-anchor" href="#add-a-pre-request-script" aria-hidden="true">#</a></h2><p>Before we do some request, create a new request to <code>/login</code> in Postman, save it to your collection and add in the form data (email and password). Add an <code>Accept</code> header with <code>application/json</code> too, so you get back JSON.</p><p><img src="'+l+'" alt="login"></p><p>No surprise here, we get back a CSRF token mismatch error.</p><p>So, let&#39;s add that pre-request script to grab the CSRF token using Sanctum, setting the value in our Postman environment variables.</p><p>Edit your collection and switch to the Pre-request Scripts tab, and add the following.</p><p><img src="'+u+`" alt="Pre request"></p><p>Don&#39;t type it from the screenshot, copy it from here:</p><div class="language-js"><pre><code>pm<span class="token punctuation">.</span><span class="token function">sendRequest</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
    <span class="token literal-property property">url</span><span class="token operator">:</span> <span class="token string">&#39;http://localhost:8000/sanctum/csrf-cookie&#39;</span><span class="token punctuation">,</span>
    <span class="token literal-property property">method</span><span class="token operator">:</span> <span class="token string">&#39;GET&#39;</span>
<span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token parameter">error<span class="token punctuation">,</span> response<span class="token punctuation">,</span> <span class="token punctuation">{</span> cookies <span class="token punctuation">}</span></span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>error<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        pm<span class="token punctuation">.</span>environment<span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span><span class="token string">&#39;xsrf-token&#39;</span><span class="token punctuation">,</span> cookies<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&#39;XSRF-TOKEN&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre></div><p>Click Update and that&#39;ll be saved.</p><p>Now make another request to /login. This time, the pre-request script will be run and will set the cookie we get back from the /sanctum/csrf-cookie endpoint into our environment.</p><p>Hit the eye icon in the top right to check.</p><p><img src="`+d+'" alt="Csrf cookie"></p><p>Great, that&#39;s our CSRF token value.</p>',29),_=t("p",null,[t("img",{src:h,alt:"X xsrf token"})],-1),b=s('<p>Hopefully that worked for you. If not, you may have to check your Sanctum setup.</p><h2 id="make-authenticated-requests" tabindex="-1">Make authenticated requests <a class="header-anchor" href="#make-authenticated-requests" aria-hidden="true">#</a></h2><p>So we&#39;ve sorted CSRF, now we&#39;ll make a request to <code>/api/users</code> to verify we&#39;re actually authenticated. Create a request for this in Postman and add it to your collection. And of course, send that request.</p><p><img src="'+k+'" alt="Unauthenticated"></p><p>Hmm, unauthenticated.</p><p>Now, this should actually work. Postman has stored the cookies we got back from making the earlier request to /login and will send them along with this request. You can verify this by clicking the cookies link to the top right of your request.</p><p><img src="'+m+`" alt="Cookies"></p><p>The reason this isn&#39;t working is that Sanctum is denying the authenticated request based on the referrer.</p><p>If you&#39;re interested in diving into some Sanctum code and figuring out why, open up the EnsureFrontendRequestsAreStateful middleware and check out the fromFrontend method that all requests are piped through.</p><div class="language-php"><pre><code><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">function</span> <span class="token function-definition function">fromFrontend</span><span class="token punctuation">(</span><span class="token variable">$request</span><span class="token punctuation">)</span>
<span class="token punctuation">{</span>
    <span class="token variable">$referer</span> <span class="token operator">=</span> <span class="token class-name static-context">Str</span><span class="token operator">::</span><span class="token function">replaceFirst</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;https://&#39;</span><span class="token punctuation">,</span> <span class="token string single-quoted-string">&#39;&#39;</span><span class="token punctuation">,</span> <span class="token variable">$request</span><span class="token operator">-&gt;</span><span class="token property">headers</span><span class="token operator">-&gt;</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;referer&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

    <span class="token variable">$referer</span> <span class="token operator">=</span> <span class="token class-name static-context">Str</span><span class="token operator">::</span><span class="token function">replaceFirst</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;http://&#39;</span><span class="token punctuation">,</span> <span class="token string single-quoted-string">&#39;&#39;</span><span class="token punctuation">,</span> <span class="token variable">$referer</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

    <span class="token keyword">return</span> <span class="token class-name static-context">Str</span><span class="token operator">::</span><span class="token function">startsWith</span><span class="token punctuation">(</span><span class="token variable">$referer</span><span class="token punctuation">,</span> <span class="token function">config</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;sanctum.stateful&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token operator">||</span>
            <span class="token class-name">Str</span><span class="token operator">::</span><span class="token function">is</span><span class="token punctuation">(</span><span class="token function">config</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;sanctum.stateful&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token variable">$referer</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre></div><p>It&#39;s checking the referrer!</p><p>At the moment in Postman, this isn&#39;t set, so add it to your headers list and send the request again.</p><p><img src="`+n+'" alt="Users list"></p><p>And there you go, a successful request to an authenticated endpoint.</p><p>It&#39;s best at this point to save your domain in an environment variable in Postman. If this changes and you have a lot of endpoints, this&#39;ll be a nightmare to update.</p><p>Click the cog in the top right, select your environment and manually add in your host.</p><p><img src="'+g+'" alt="Localhost port"></p><hr><p><img src="'+v+'" alt="Env name"></p><p>Once you&#39;ve saved that, switch out the header value and send the request again.</p><p><img src="'+n+'" alt="Users list"></p><p>Still works. Great.</p><p>You&#39;ll need to add the Referrer header to all requests you make to your API, if they&#39;re protected with Sanctum. That&#39;s not too much trouble, though.</p><h2 id="a-quick-note-on-other-web-routes" tabindex="-1">A quick note on other web routes <a class="header-anchor" href="#a-quick-note-on-other-web-routes" aria-hidden="true">#</a></h2><p>Sanctum let&#39;s us use the normal /login web route to authenticate, but that&#39;s not all. We can also hit /logout to invalidate the authenticated cookie value.</p><p>For these other web routes (also CSRF protected), you need to ensure you&#39;re also sending the token down. Here&#39;s a quick example.</p><p><img src="'+f+'" alt="logout"></p><p>My request to /logout was successful because I&#39;m sending down the X-XSRF-TOKEN header, much like we did for /login.</p><p><a href="https://blog.codecourse.com/laravel-sanctum-airlock-with-postman/" target="_blank" rel="noopener noreferrer">https://blog.codecourse.com/laravel-sanctum-airlock-with-postman/</a></p>',29);function q(e,S,P,C,A,j){return r(),p("div",null,[y,t("p",null,"Now update the /login request to add the X-XSRF-TOKEN header with the value "+a(e.xsrf-e.token)+" (this is the value of our environment variable), and send the request again.",1),_,t("p",null,"Make sure you don't include spaces between the curly braces (e.g. "+a(e.xsrf-e.token)+"). Postman doesn't like that.",1),b])}var F=o(w,[["render",q]]);export{R as __pageData,F as default};
